                    dp[i] = dp[i - 1];
                }else{
                    dp[i] = dp[i - 1] - (back[a[i] - 1]) + 1;
                    back[a[i] - 1] = 0;
                    back[a[i]]++;
                }
            }
            front[a[i]]--;
        }

        cout << n - dp[n - 1] << '\n';
    }
    return 0;
}

